import { useEvent } from "../../../../hooks/use-event.js";
export function useRowDetailToggle(api, detailExpansions, onRowDetailExpansionsChange) {
    return useEvent((row, state) => {
        const id = typeof row === "string" ? row : typeof row === "number" ? api.rowByIndex(row).get()?.id : row.id;
        if (!id)
            return;
        const next = new Set([...detailExpansions]);
        const nextState = state ?? !next.has(id);
        if (nextState)
            next.add(id);
        else
            next.delete(id);
        onRowDetailExpansionsChange(next);
    });
}
